{
 "level": "B1",
 "intro": "In this topic, you will learn to build <strong>negative and interrogative sentences</strong> in the passive voice, as well as give <strong>short answers</strong> to yes/no questions.",
 "rules": [
 {
 "label": "Denial",
 "color": "rose",
 "text": "Add <strong>not</strong> after be:",
 "example": "The house isn't made of wood."
 },
 {
 "label": "Question",
 "color": "blue",
 "text": "<strong>be</strong> comes first:",
 "example": "Was it built in 1990?"
 },
 {
 "label": "Short answers",
 "color": "emerald",
 "text": "<strong>Yes/No + subject + be</strong>:",
 "example": "Yes, it was. / No, it wasn't."
 }
 ]
}

{
 "title": "1. Negation in the Present Simple Passive",
 "sections": [
 {
 "label": "Structure",
 "color": "rose",
 "description": "Formula: <strong>am/is/are + not + V3</strong>. Abbreviated forms: <strong>isn't, aren't</strong>",
 "examples": [
 {
 "en": "The products are not made in China.",
 "ua": "The products are not made in China."
 },
 {
 "en": "This material isn't used anymore.",
 "ua": "This material isn't used anymore."
 },
 {
 "en": "I am not invited to the party.",
 "ua": "I am not invited to the party."
 },
 {
 "en": "The doors aren't locked at night.",
 "ua": "The doors aren't locked at night."
 }
 ]
 },
 {
 "label": "Nuances",
 "color": "amber",
 "description": "The form <strong>am not</strong> is not shortened to \"amn't\". We use: <strong>I'm not</strong>",
 "examples": {
 "en": "I'm not included in the list.",
 "ua": "I'm not included in the list."
 }
 }
 ]
}

{
 "title": "2. Denial in the Past Simple Passive",
 "sections": {
 "label": "Structure",
 "color": "rose",
 "description": "Formula: <strong>was/were + not + V3</strong>. Abbreviated: <strong>wasn't, weren't</strong>",
 "examples": [
 {
 "en": "The house was not built in 1990.",
 "ua": "The house was not built in 1990."
 },
 {
 "en": "The letter wasn't sent yesterday.",
 "ua": "The letter wasn't sent yesterday."
 },
 {
 "en": "We were not informed about the changes.",
 "ua": "We were not informed about the changes."
 },
 {
 "en": "The tickets weren't sold out.",
 "ua": "The tickets weren't sold out."
 }
 ]
 }
}

{
 "title": "3. Denial in other times",
 "sections": [
 {
 "label": "Future Simple",
 "color": "rose",
 "description": "<strong>will not (won't) + be + V3</strong>",
 "examples": [
 {
 "en": "The project will not be finished on time.",
 "ua": "The project will not be finished on time."
 },
 {
 "en": "The meeting won't be held tomorrow.",
 "ua": "The meeting won't be held tomorrow."
 }
 ]
 },
 {
 "label": "Present Perfect",
 "color": "rose",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "The work has not been completed yet.",
 "ua": "The work has not been completed yet."
 },
 {
 "en": "The files haven't been uploaded.",
 "ua": "The files haven't been uploaded."
 }
 ]
 }
 ]
}

{
 "title": "4. Yes/No questions in the passive voice",
 "sections": [
 {
 "label": "Present Simple",
 "color": "blue",
 "description": "<strong>Am/Is/Are + S + V3?</strong>",
 "examples": [
 {
 "en": "Is English spoken here?",
 "ua": "Is English spoken here?"
 },
 {
 "en": "Are the rooms cleaned daily?",
 "ua": "Are the rooms cleaned daily?"
 },
 {
 "en": "Am I included in the team?",
 "ua": "Am I included in the team?"
 }
 ]
 },
 {
 "label": "Past Simple",
 "color": "blue",
 "description": "<strong>Was/Were + S + V3?</strong>",
 "examples": [
 {
 "en": "Was the house built in 1990?",
 "ua": "Was the house built in 1990?"
 },
 {
 "en": "Were the documents signed?",
 "ua": "Were the documents signed?"
 }
 ]
 },
 {
 "label": "Future Simple",
 "color": "blue",
 "description": "<strong>Will + S + be + V3?</strong>",
 "examples": [
 {
 "en": "Will the project be finished on time?",
 "ua": "Will the project be finished on time?"
 },
 {
 "en": "Will you be invited to the meeting?",
 "ua": "Will you be invited to the meeting?"
 }
 ]
 },
 {
 "label": "Present Perfect",
 "color": "blue",
 "description": "<strong>Has/Have + S + been + V3?</strong>",
 "examples": [
 {
 "en": "Has the work been completed?",
 "ua": "Has the work been completed?"
 },
 {
 "en": "Have the tickets been sold?",
 "ua": "Have the tickets been sold?"
 }
 ]
 }
 ]
}

{
 "title": "5. Short answers (Short Answers)",
 "sections": [
 {
 "label": "Rule",
 "color": "emerald",
 "description": "Structure: <strong>Yes/No + subject pronoun + be (at the same time)</strong>",
 "examples": [
 {
 "en": "Is the door locked? — Yes, it is. / No, it isn't.",
 "ua": "Is the door locked? — Yes, it is. / No, it isn't."
 },
 {
 "en": "Was the letter sent? — Yes, it was. / No, it wasn't.",
 "ua": "Was the letter sent? — Yes, it was. / No, it wasn't."
 },
 {
 "en": "Are they invited? — Yes, they are. / No, they aren't.",
 "ua": "Are they invited? — Yes, they are. / No, they aren't."
 }
 ]
 },
 {
 "label": "Present Perfect",
 "color": "emerald",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Has the work been finished? — Yes, it has. / No, it hasn't.",
 "ua": "Has the work been finished? — Yes, it has. / No, it hasn't."
 },
 {
 "en": "Have they been informed? — Yes, they have. / No, they haven't.",
 "ua": "Have they been informed? — Yes, they have. / No, they haven't."
 }
 ]
 },
 {
 "label": "Future Simple",
 "color": "emerald",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": {
 "en": "Will it be done tomorrow? — Yes, it will. / No, it won't.",
 "ua": "Will it be done tomorrow? — Yes, it will. / No, it won't."
 }
 }
 ]
}

{
 "title": "6. Wh-question in the passive",
 "sections": [
 {
 "label": "Structure",
 "color": "sky",
 "description": "<strong>Wh-word + be + S + V3?</strong>",
 "examples": [
 {
 "en": "Where is coffee grown?",
 "ua": "Where is coffee grown?"
 },
 {
 "en": "When was the house built?",
 "ua": "When was the house built?"
 },
 {
 "en": "How are these products made?",
 "ua": "How are these products made?"
 },
 {
 "en": "Why was the meeting cancelled?",
 "ua": "Why was the meeting cancelled?"
 }
 ]
 },
 {
 "label": "Who/What as subject",
 "color": "sky",
 "description": "When the question word is the subject: <strong>Who/What + be + V3?</strong> (without inversion)",
 "examples": [
 {
 "en": "What is produced here?",
 "ua": "What is produced here?"
 },
 {
 "en": "Who was invited to the party?",
 "ua": "Who was invited to the party?"
 }
 ]
 }
 ]
}

{
 "title": "7. Summary table of questions and negatives",
 "intro": "The main structures of negatives and questions at different times:",
 "rows": [
 {
 "en": "Present Simple",
 "ua": "Present Simple",
 "note": "Is it made here? — Yes, it is. / No, it isn't."
 },
 {
 "en": "Past Simple",
 "ua": "Past Simple",
 "note": "Was it built in 1990? — Yes, it was. / No, it wasn't."
 },
 {
 "en": "Future Simple",
 "ua": "Future Simple",
 "note": "Will it be finished? — Yes, it will. / No, it won't."
 },
 {
 "en": "Present Perfect",
 "ua": "Present Perfect",
 "note": "Has it been done? — Yes, it has. / No, it hasn't."
 }
 ]
}

{
 "title": "8. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "The word order in the question is incorrect.",
 "wrong": "The house was built in 1990?",
 "right": "✅ Was the house built in 1990?"
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Omission of the auxiliary verb in the question.",
 "wrong": "It made in China?",
 "right": "✅ Is it made in China?"
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Incomplete short answer.",
 "wrong": "Was it built? — Yes, it.",
 "right": "✅ Yes, it was."
 }
 ]
}

{
 "title": "9. Short summary",
 "items": [
 "Negation: <strong>be + not + V3</strong> (isn't, wasn't, won't be, hasn't been).",
 "Yes/No question: <strong>be</strong> comes first before the subject.",
 "Short answers: <strong>Yes/No + subject + be</strong> (at the same time).",
 "Wh-question: <strong>Wh-word + be + S + V3?</strong>",
 "When Who/What is the subject, no inversion is needed: <strong>What is produced?</strong>"
 ]
}
